      wb_rfd_adr_o <= ctrl_rfd_adr_o;

+
+/*----------------Formal Checking-----------------*/
+
+`ifdef FORMAL
+
+   reg f_past_valid;
+   initial f_past_valid = 1'b0;
+   initial assume (rst);
+
+   always @(posedge clk)
+      f_past_valid <= 1'b1;
+
+   always @(posedge clk)
