   reg f_past_valid;
   (* anyconst *) wire [ADDR_WIDTH-1:0] f_addr;
   (* anyconst *) reg [DATA_WIDTH-1:0] f_data;

   initial f_past_valid = 1'b0;
   always @(posedge clk)
      f_past_valid <= 1'b1;

`ifdef SDPRAM

   reg f_written = 0;
   initial f_written = 0;

   //Writing f_data at address f_addr
   always @(posedge clk)
      if (f_past_valid && $past(we) && $past(waddr) == f_addr && !ENABLE_BYPASS && $past(din) == f_data)
         f_written <= 1;

