`ifdef FORMAL

`ifdef BUFFER
`define ASSUME assume
`else
`define ASSUME assert
`endif

   reg f_past_valid;
   initial f_past_valid = 1'b0;
   always @(posedge clk)
      f_past_valid <= 1;
   always @(posedge clk)
