`define ASSUME assume
`else
`define ASSUME assert
`endif

`ifdef TDPRAM

   always @(*)
      `ASSUME (addr_a != addr_b);

   (* anyconst *) wire [ADDR_WIDTH-1:0] f_addr;
   (* anyconst *) reg [DATA_WIDTH-1:0] f_data_a;
   (* anyconst *) reg [DATA_WIDTH-1:0] f_data_b;

   reg f_write_a = 0;
